template <typename T>
class Trie01Vector {
private:
	struct TrieNode {
		array<int, 2> children; // 指向孩子的 id
		int cntA[2];  // 记录经过该节点，且 a 在这一位是 0/1 的数字个数
		TrieNode() : children{ 0, 0 }, cntA{ 0, 0 } {}
	};

	vector<TrieNode> tr;
	int newNode() { tr.push_back(TrieNode()); return ++nodeCnt; }

	int MAX; 	      // MAX：数的最大二进制位数
	int nodeCnt = 1;
	int root = 1;

public:
	Trie01Vector(int MAX) :MAX(MAX), tr(2) {}

	void insert(int num, int a) {
		int now = root;
		for (int i = MAX; i >= 0; i--) {
			bool bit = (num >> i) & 1;
			if (!tr[now].children[bit]) {
				int tmp = newNode();
				tr[now].children[bit] = tmp;
			}
			now = tr[now].children[bit];

			bool a_bit = (a >> i) & 1;
			tr[now].cntA[a_bit]++;
		}
	}

	ll query(int num, int a) {
		int now = root;
		ll res = 0;
		for (int i = MAX; i >= 0; i--) {
			bool bit = (num >> i) & 1;

			if (tr[now].children[!bit]) {
				bool t = (a >> i) & 1;
				res += tr[tr[now].children[!bit]].cntA[t];
			}

			if (tr[now].children[bit])now = tr[now].children[bit];
			else break;
		}
		return res;
	}
};
void solve(int CASE)
{
	int n, k1, k2; cin >> n >> k1 >> k2;
	var a = vector<int>(n + 1);
	var b = vector<int>(n + 1);
	fa(i, 1, n)cin >> a[i];
	fa(i, 1, n)cin >> b[i];
	var t = Trie01Vector<ll>(30);
	ll ans = 0;
	fa(i, 1, n) {
		ans += t.query(a[i] ^ b[i], a[i] ^ k1);
		t.insert(k1 ^ k2 ^ a[i] ^ b[i], a[i]);
	}
	cout << ans << endl;
	return;
}
